import{_ as a,c as e,o as t,ag as o}from"./chunks/framework.CkHWihve.js";const i="/workspace-navigation-home.png",k=JSON.parse('{"title":"Workspaces","description":"","frontmatter":{},"headers":[],"relativePath":"docs/workspaces.md","filePath":"docs/workspaces.md"}'),n={name:"docs/workspaces.md"};function r(p,s,c,l,h,d){return t(),e("div",null,s[0]||(s[0]=[o(`<h1 id="workspaces" tabindex="-1">Workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;Workspaces&quot;">​</a></h1><p>Compas comes with out-of-the-box support for workspaces. All <a href="/docs/actions-and-defaults.html">actions and defaults</a> from the previous chapter are executed for the known projects in a workspace. Allowing you to run Compas once and get the benefits for all projects that you are working on simultaneously.</p><h2 id="enabling-workspaces" tabindex="-1">Enabling workspaces <a class="header-anchor" href="#enabling-workspaces" aria-label="Permalink to &quot;Enabling workspaces&quot;">​</a></h2><p>The configuration file <code>config/compas.json</code> allows you to define related projects, for example:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;projects&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;packages/shared&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This registers a sub project in <code>$root/packages/shared</code>. All automatic actions that Compas executes are now also done relative to that directory. You can create another config in <code>$root/packages/shared/config/compas.json</code> to define custom actions for that specific project and to add even more nested projects.</p><p>Navigation to subprojects is automatically added:</p><p><img src="`+i+`" alt="Navigation from the root project"></p><p>Compas also allows projects to be in a sibling directory:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">	&quot;projects&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;../project-frontend&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>In this case, the sibling directory is optional and not loaded if it can not be found. It is also allowed to create recursive project references, so you can set up Compas in all individual projects, and it automatically includes the other projects when they are found. Giving the same experience no matter which project you are currently working on.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Compas assumes that nested projects are also setup correctly in your package manager and only runs installation (e.g <code>npm install</code>) in the root project. For sibling projects, Compas runs the inferred package manager in each project.</li><li>Compas stores its cache in the project that you started Compas in and removes the cache from referenced projects. This way Compas has a single source of truth. So the most efficient way of developing is to always start Compas from the same project and to navigate inside Compas to other projects when necessary.</li><li>Only 9 subprojects are supported currently.</li></ul>`,13)]))}const g=a(n,[["render",r]]);export{k as __pageData,g as default};
